class RBAC:
    def __init__(self):
        self.roles = {}
        self.users = {}
    def add_role(self, role, perms):
        self.roles[role] = set(perms)
    def assign(self, user, role):
        self.users[user] = role
    def check(self, user, perm):
        role = self.users.get(user)
        if not role: return False
        return perm in self.roles.get(role, set())

rbac = RBAC()
rbac.add_role('admin', ['read','write','delete'])
rbac.add_role('viewer', ['read'])
rbac.assign('alice', 'admin')
rbac.assign('bob', 'viewer')
for u in ['alice','bob']:
    for p in ['read','delete']:
        print(f'{u} -> {p}: {rbac.check(u, p)}')

